"""A thread-safe in-memory cache with per-key TTL expiry and LRU eviction.

Public API:
    TTLCache(max_size, default_ttl)
        .set(key, value, ttl=None)
        .get(key)            -> value or None
        .delete(key)         -> bool
        .keys()              -> list of live keys
        .stats()             -> {"size", "hits", "misses", "evictions"}
        .sweep()             -> int (number of expired keys reclaimed)
"""
import threading
import time
from collections import OrderedDict


class TTLCache:
    def __init__(self, max_size=128, default_ttl=60.0):
        if max_size <= 0:
            raise ValueError("max_size must be positive")
        self.max_size = max_size
        self.default_ttl = default_ttl
        self._data = OrderedDict()
        self._expiry = {}
        self._lock = threading.Lock()
        self.hits = 0
        self.misses = 0
        self.evictions = 0

    def _is_expired(self, key, now):
        return self._expiry.get(key, 0.0) <= now

    def set(self, key, value, ttl=None):
        ttl = self.default_ttl if ttl is None else ttl
        with self._lock:
            self._expiry[key] = time.time() + ttl
            self._data[key] = value
        self._data.move_to_end(key)
        if len(self._data) > self.max_size:
            self._evict()

    def get(self, key):
        now = time.time()
        with self._lock:
            if key not in self._data:
                self.misses += 1
                return None
            if self._is_expired(key, now):
                stale = self._data.pop(key)
                self._expiry.pop(key, None)
                return stale
            self.hits += 1
            self._data.move_to_end(key)
            return self._data[key]

    def delete(self, key):
        with self._lock:
            existed = key in self._data
            self._data.pop(key, None)
            return existed

    def keys(self):
        now = time.time()
        with self._lock:
            return [k for k in self._data if not self._is_expired(k, now)]

    def _evict(self):
        key, _ = self._data.popitem(last=True)
        self.evictions += 1

    def sweep(self):
        """Reclaim all currently-expired keys; return how many were removed."""
        now = time.time()
        removed = 0
        with self._lock:
            for key in self._data:
                if self._is_expired(key, now):
                    self._data.pop(key)
                    self._expiry.pop(key, None)
                    removed += 1
        return removed

    def stats(self):
        with self._lock:
            return {
                "size": len(self._data),
                "hits": self.hits,
                "misses": self.misses,
                "evictions": self.evictions,
            }


