"""Test suite for buggy_cache.TTLCache."""
import threading
import time

import pytest

from buggy_cache import TTLCache


def test_lru_eviction_drops_least_recently_used():
    c = TTLCache(max_size=2, default_ttl=100)
    c.set("a", 1)
    c.set("b", 2)
    assert c.get("a") == 1
    c.set("c", 3)
    assert c.get("a") == 1
    assert c.get("c") == 3
    assert c.get("b") is None


def test_ttl_boundary_is_inclusive():
    c = TTLCache(default_ttl=100)
    c.set("k", "v", ttl=50)
    assert c.get("k") == "v"


def test_expired_key_never_returns_stale_value():
    c = TTLCache(default_ttl=0.05)
    c.set("k", "v")
    time.sleep(0.12)
    assert c.get("k") is None


def test_expiry_index_does_not_leak_on_eviction():
    c = TTLCache(max_size=4, default_ttl=100)
    for i in range(200):
        c.set(f"k{i}", i)
    assert len(c._expiry) <= c.max_size


def test_delete_cleans_expiry_index():
    c = TTLCache(default_ttl=100)
    c.set("k", 1)
    assert c.delete("k") is True
    assert "k" not in c._expiry
    assert c.delete("k") is False


def test_sweep_reclaims_expired_without_crashing():
    c = TTLCache(default_ttl=0.05)
    for i in range(10):
        c.set(f"k{i}", i)
    time.sleep(0.12)
    removed = c.sweep()
    assert removed == 10
    assert c.stats()["size"] == 0


def test_concurrent_sets_respect_capacity():
    c = TTLCache(max_size=50, default_ttl=100)

    def worker(n):
        for i in range(300):
            c.set(f"{n}-{i}", i)

    threads = [threading.Thread(target=worker, args=(n,)) for n in range(8)]
    for t in threads:
        t.start()
    for t in threads:
        t.join()
    assert len(c._data) <= c.max_size
    assert len(c._data) == len(c._expiry)


if __name__ == "__main__":
    raise SystemExit(pytest.main([__file__, "-v"]))


