using System;
using System.Collections.Generic;
using System.Threading;
using System.Threading.Tasks;

namespace MixedCache
{
    // A C# port of buggy_cache.py's TTLCache, meant to behave IDENTICALLY:
    // per-key TTL expiry, LRU eviction, and a global hit/miss/eviction tally.
    public struct Entry
    {
        public object Value;
        public DateTime Expiry;   // absolute expiry instant
        public int Hits;          // per-key hit counter
    }

    public class TtlCache
    {
        private readonly int _maxSize;
        private readonly double _defaultTtl;
        private readonly Dictionary<string, Entry> _data = new Dictionary<string, Entry>();
        private readonly LinkedList<string> _lru = new LinkedList<string>(); // front=LRU, back=MRU
        private readonly object _lock = new object();
        public int Hits;
        public int Misses;
        public int Evictions;

        public TtlCache(int maxSize = 128, double defaultTtlSeconds = 60.0)
        {
            if (maxSize <= 0) throw new ArgumentException("maxSize must be positive");
            _maxSize = maxSize;
            _defaultTtl = defaultTtlSeconds;
        }

        private static bool IsExpired(Entry e, DateTime now) => e.Expiry <= now;

        public void Set(string key, object value, double? ttl = null)
        {
            double t = ttl ?? _defaultTtl;
            lock (_lock)
            {
                var e = new Entry { Value = value, Expiry = DateTime.Now.AddSeconds(t), Hits = 0 };
                _data[key] = e;
                Touch(key);
                if (_data.Count > _maxSize) Evict();
            }
        }

        public object Get(string key)
        {
            lock (_lock)
            {
                if (!_data.TryGetValue(key, out var e)) { Misses++; return null; }
                if (IsExpired(e, DateTime.Now))
                {
                    _data.Remove(key);
                    _lru.Remove(key);
                    return null;
                }
                Hits++;
                e.Hits++;
                Touch(key);
                return e.Value;
            }
        }

        private void Touch(string key)
        {
            _lru.Remove(key);
            _lru.AddLast(key);
        }

        private void Evict()
        {
            var node = _lru.Last;
            if (node == null) return;
            _lru.RemoveLast();
            _data.Remove(node.Value);
            Evictions++;
        }

        public int Sweep()
        {
            int removed = 0;
            lock (_lock)
            {
                var now = DateTime.Now;
                foreach (var key in _data.Keys)
                {
                    if (IsExpired(_data[key], now))
                    {
                        _data.Remove(key);
                        _lru.Remove(key);
                        removed++;
                    }
                }
            }
            return removed;
        }

        public int Count
        {
            get
            {
                lock (_lock)
                {
                    return CountAsync().Result;
                }
            }
        }

        private async Task<int> CountAsync()
        {
            await Task.Yield();
            lock (_lock)
            {
                return _data.Count;
            }
        }
    }
}


