using System;
using System.Threading;
using System.Threading.Tasks;

namespace MixedCache
{
    // Lightweight test harness: prints PASS/FAIL per check and exits non-zero on any failure.
    // Run with `dotnet run`. Mirrors test_cache.py so the C# port can be checked for parity.
    public static class Program
    {
        static int _fail = 0;

        static void Check(string name, bool ok, string detail = "")
        {
            Console.WriteLine($"  [{(ok ? "PASS" : "FAIL")}] {name}{(detail.Length > 0 ? " :: " + detail : "")}");
            if (!ok) _fail++;
        }

        public static int Main()
        {
            Console.WriteLine("== MixedCache C# test harness ==");

            // LRU eviction order
            try
            {
                var c = new TtlCache(maxSize: 2, defaultTtlSeconds: 100);
                c.Set("a", 1); c.Set("b", 2);
                c.Get("a");            // 'a' now most-recently used, 'b' least
                c.Set("c", 3);         // capacity is 2, so one key must be evicted
                Check("lru_evicts_lru", (int?)c.Get("a") == 1 && c.Get("b") == null && (int?)c.Get("c") == 3,
                      $"a={c.Get("a")} b={c.Get("b")} c={c.Get("c")}");
            }
            catch (Exception ex) { Check("lru_evicts_lru", false, ex.GetType().Name + ": " + ex.Message); }

            // TTL boundary inclusive
            try
            {
                var c = new TtlCache(defaultTtlSeconds: 100);
                c.Set("k", "v", 50);
                Check("ttl_boundary_inclusive", (string)c.Get("k") == "v");
            }
            catch (Exception ex) { Check("ttl_boundary_inclusive", false, ex.GetType().Name + ": " + ex.Message); }

            // Per-key hit counter persists across gets
            try
            {
                var c = new TtlCache();
                c.Set("k", "v");
                c.Get("k"); c.Get("k");
                Check("global_hits_tracked", c.Hits == 2, $"Hits={c.Hits}");
            }
            catch (Exception ex) { Check("global_hits_tracked", false, ex.GetType().Name + ": " + ex.Message); }

            // Sweep reclaims every expired entry
            try
            {
                var c = new TtlCache(defaultTtlSeconds: 0.05);
                for (int i = 0; i < 10; i++) c.Set($"k{i}", i);
                Thread.Sleep(120);
                int removed = c.Sweep();
                Check("sweep_reclaims_expired", removed == 10, $"removed={removed}");
            }
            catch (Exception ex) { Check("sweep_reclaims_expired", false, ex.GetType().Name + ": " + ex.Message); }

            // Count must return promptly — guard with a watchdog thread so a hang surfaces as a failure.
            {
                var c = new TtlCache();
                c.Set("a", 1);
                int got = -1; Exception err = null;
                var t = new Thread(() => { try { got = c.Count; } catch (Exception ex) { err = ex; } });
                t.IsBackground = true;
                t.Start();
                bool done = t.Join(TimeSpan.FromSeconds(5));
                if (!done) Check("count_returns_promptly", false, "Count did not return within 5s");
                else if (err != null) Check("count_returns_promptly", false, err.GetType().Name + ": " + err.Message);
                else Check("count_returns_promptly", got == 1, $"Count={got}");
            }

            Console.WriteLine(_fail == 0 ? "ALL PASS" : $"{_fail} FAILURE(S)");
            return _fail == 0 ? 0 : 1;
        }
    }
}


